  1→import { createContext, useContext, useReducer } from 'react';
  2→import { createProject } from '@/domain/models';
  3→import { createDuplicatedFloor, getDefaultFloorName, getFloorElevation, getFloorLevelIndex, shiftFloorAbsoluteElements, shiftFloorElevationData, sortFloors } from '@/domain/floorModels';
  4→import { detachColumnAttachments, syncWallAttachmentPoints } from '@/geometry/wallColumnGeometry';
  5→
  6→const ProjectContext = createContext(null);
  7→const HISTORY_LIMIT = 100;
  8→
  9→function snapshotProject(project) {
 10→  return JSON.stringify(project);
 11→}
 12→
 13→function applyProjectUpdate(state, nextProject, recordHistory = true) {
 14→  const nextSnapshot = snapshotProject(nextProject);
 15→  const history = recordHistory
 16→    ? [...state.history, state.project].slice(-HISTORY_LIMIT)
 17→    : state.history;
 18→
 19→  return {
 20→    ...state,
 21→    history,
 22→    future: recordHistory ? [] : state.future,
 23→    project: nextProject,
 24→    isDirty: nextSnapshot !== state.savedSnapshot,
 25→  };
 26→}
 27→
 28→function updateFloor(state, floorId, updater, recordHistory = true, options = {}) {
 29→  const nextFloors = state.project.floors.map((floor) => (
 30→    floor.id === floorId ? updater(floor) : floor
 31→  ));
 32→
 33→  return applyProjectUpdate(state, {
 34→    ...state.project,
 35→    updatedAt: new Date().toISOString(),
 36→    floors: options.sort ? sortFloors(nextFloors) : nextFloors,
 37→  }, recordHistory);
 38→}
 39→
 40→function replaceFloors(state, floors, recordHistory = true) {
 41→  return applyProjectUpdate(state, {
 42→    ...state.project,
 43→    updatedAt: new Date().toISOString(),
 44→    floors: sortFloors(floors),
 45→  }, recordHistory);
 46→}
 47→
 48→function replaceDeletedFloorReferences(project, deletedFloorId, fallbackFloorId) {
 49→  return {
 50→    ...project,
 51→    floors: project.floors.map((floor) => ({
 52→      ...floor,
 53→      stairs: (floor.stairs || []).map((stair) => ({
 54→        ...stair,
 55→        floorRelation: {
 56→          fromFloorId: stair.floorRelation?.fromFloorId === deletedFloorId
 57→            ? fallbackFloorId
 58→            : (stair.floorRelation?.fromFloorId ?? floor.id),
 59→          toFloorId: stair.floorRelation?.toFloorId === deletedFloorId
 60→            ? fallbackFloorId
 61→            : (stair.floorRelation?.toFloorId ?? floor.id),
 62→        },
 63→      })),
 64→    })),
 65→    sheets: (project.sheets || []).map((sheet) => ({
 66→      ...sheet,
 67→      viewports: (sheet.viewports || []).map((viewport) => ({
 68→        ...viewport,
 69→        sourceFloorId: viewport.sourceFloorId === deletedFloorId
 70→          ? fallbackFloorId
 71→          : viewport.sourceFloorId,
 72→        sourceRefId: viewport.sourceFloorId === deletedFloorId
 73→          ? null
 74→          : viewport.sourceRefId,
 75→      })),
 76→    })),
 77→  };
 78→}
 79→
 80→function mergeWallUpdate(existingWall, wallUpdate, columns = []) {
 81→  const nextWall = { ...existingWall, ...wallUpdate };
 82→
 83→  if ('start' in wallUpdate && !('startAttachment' in wallUpdate)) {
 84→    nextWall.startAttachment = null;
 85→  }
 86→  if ('end' in wallUpdate && !('endAttachment' in wallUpdate)) {
 87→    nextWall.endAttachment = null;
 88→  }
 89→
 90→  return syncWallAttachmentPoints(nextWall, columns);
 91→}
 92→
 93→function projectReducer(state, action) {
 94→  switch (action.type) {
 95→    case 'PROJECT_NEW': {
 96→      const newProject = {
 97→        ...action.project,
 98→        floors: sortFloors(action.project.floors || []),
 99→      };
100→      return {
101→        project: newProject,
102→        isDirty: false,
103→        lastSavedAt: null,
104→        savedSnapshot: snapshotProject(newProject),
105→        history: [],
106→        future: [],
107→      };
108→    }
109→
110→    case 'PROJECT_LOAD': {
111→      const loadedProject = {
112→        ...action.project,
113→        floors: sortFloors(action.project.floors || []),
114→      };
115→      return {
116→        project: loadedProject,
117→        isDirty: false,
118→        lastSavedAt: action.savedAt || null,
119→        savedSnapshot: snapshotProject(loadedProject),
120→        history: [],
121→        future: [],
122→      };
123→    }
124→
125→    case 'PROJECT_SET_NAME':
126→      return applyProjectUpdate(state, {
127→        ...state.project,
128→        name: action.name,
129→        updatedAt: new Date().toISOString(),
130→      });
131→
132→    case 'FLOOR_ADD':
133→      return replaceFloors(state, [...state.project.floors, action.floor]);
134→
135→    case 'FLOOR_UPDATE':
136→      return updateFloor(state, action.floor.id, (floor) => {
137→        const mergedFloor = {
138→          ...floor,
139→          ...action.floor,
140→        };
141→        const nextElevation = getFloorElevation(mergedFloor);
142→        const deltaElevation = nextElevation - getFloorElevation(floor);
143→        return {
144→          ...shiftFloorAbsoluteElements({
145→            ...mergedFloor,
146→            elevation: getFloorElevation(floor),
147→          }, deltaElevation),
148→          elevation: nextElevation,
149→        };
150→      }, true, { sort: true });
151→
152→    case 'FLOOR_DUPLICATE': {
153→      const duplicatedFloor = action.floor;
154→      const elevationShift = duplicatedFloor.floorToFloorHeight ?? 0;
155→      const insertionLevelIndex = getFloorLevelIndex(duplicatedFloor);
156→
157→      const shiftedFloors = state.project.floors.map((floor) => {
158→        if (getFloorLevelIndex(floor) < insertionLevelIndex) return floor;
159→
160→        const previousLevelIndex = getFloorLevelIndex(floor);
161→        return shiftFloorElevationData({
162→          ...floor,
163→          name: floor.name === getDefaultFloorName(previousLevelIndex)
164→            ? getDefaultFloorName(previousLevelIndex + 1)
165→            : floor.name,
166→          levelIndex: previousLevelIndex + 1,
167→        }, elevationShift);
168→      });
169→
170→      return replaceFloors(state, [...shiftedFloors, duplicatedFloor]);
171→    }
172→
173→    case 'FLOOR_DELETE': {
174→      if (state.project.floors.length <= 1) return state;
175→
176→      const nextProject = replaceDeletedFloorReferences(
177→        {
178→          ...state.project,
179→          floors: state.project.floors.filter((floor) => floor.id !== action.floorId),
180→        },
181→        action.floorId,
182→        action.fallbackFloorId
183→      );
184→
185→      return applyProjectUpdate(state, {
186→        ...nextProject,
187→        updatedAt: new Date().toISOString(),
188→        floors: sortFloors(nextProject.floors),
189→      });
190→    }
191→
192→    case 'SHEET_ADD':
193→      return applyProjectUpdate(state, {
194→        ...state.project,
195→        updatedAt: new Date().toISOString(),
196→        sheets: [...(state.project.sheets || []), action.sheet],
197→      });
198→
199→    case 'SHEET_UPDATE':
200→      return applyProjectUpdate(state, {
201→        ...state.project,
202→        updatedAt: new Date().toISOString(),
203→        sheets: (state.project.sheets || []).map((sheet) => (
204→          sheet.id === action.sheet.id ? { ...sheet, ...action.sheet } : sheet
205→        )),
206→      });
207→
208→    case 'SHEET_DELETE':
209→      return applyProjectUpdate(state, {
210→        ...state.project,
211→        updatedAt: new Date().toISOString(),
212→        sheets: (state.project.sheets || []).filter((sheet) => sheet.id !== action.sheetId),
213→      });
214→
215→    case 'SHEET_VIEWPORT_ADD':
