100→    { tool: TOOLS.SELECT, label: 'Select', shortcut: 'V' },
101→    { tool: TOOLS.DIMENSION, label: 'Dim', shortcut: 'M' },
102→    { tool: TOOLS.WALL, label: 'Wall', shortcut: 'W' },
103→    { tool: TOOLS.BEAM, label: 'Beam', shortcut: 'B' },
104→    { tool: TOOLS.STAIR, label: 'Stair', shortcut: 'T' },
105→    { tool: TOOLS.SECTION, label: 'Section', shortcut: 'Q' },
106→    { tool: TOOLS.SLAB, label: 'Slab', shortcut: 'S' },
107→    { tool: TOOLS.ROOM, label: 'Room', shortcut: 'R' },
108→    { tool: TOOLS.DOOR, label: 'Door', shortcut: 'D', hint: 'F to flip swing' },
109→    { tool: TOOLS.WINDOW, label: 'Window', shortcut: 'N' },
110→    { tool: TOOLS.COLUMN, label: 'Column', shortcut: 'C' },
111→  ];
112→  const activeToolLabel = toolItems.find(t => t.tool === activeTool)?.label || 'Tools';
113→  const handleUndo = useCallback(() => {
114→    if (!canUndo) return;
115→    dispatch({ type: 'UNDO' });
116→    editorDispatch({ type: 'DESELECT' });
117→    editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Undid last change.' });
118→  }, [canUndo, dispatch, editorDispatch]);
119→  const handleRedo = useCallback(() => {
120→    if (!canRedo) return;
121→    dispatch({ type: 'REDO' });
122→    editorDispatch({ type: 'DESELECT' });
123→    editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Redid last change.' });
124→  }, [canRedo, dispatch, editorDispatch]);
125→
126→  const handleDetectRooms = () => {
127→    const floor = project.floors.find(f => f.id === activeFloorId);
128→    if (!floor || floor.walls.length < 3) {
129→      editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Draw at least 3 walls first.' });
130→      return;
131→    }
132→
133→    const detected = detectRooms(floor.walls, floor.columns || []);
134→    const rooms = detected.map((d, i) => createRoom(`Room ${i + 1}`, d.points));
135→    dispatch({ type: 'ROOMS_SET', floorId: activeFloorId, rooms });
136→    editorDispatch({ type: 'DESELECT' });
137→    editorDispatch({
138→      type: 'SET_STATUS_MESSAGE',
139→      message: rooms.length ? `Detected ${rooms.length} room${rooms.length === 1 ? '' : 's'}.` : 'No enclosed rooms detected.',
140→    });
141→  };
142→
143→  useEffect(() => {
144→    const handleKeyDown = (e) => {
145→      if (!(e.ctrlKey || e.metaKey)) return;
146→      if (isTypingTarget(e.target)) return;
147→
148→      const key = e.key.toLowerCase();
149→      const isRedo = (key === 'z' && e.shiftKey) || key === 'y';
150→      const isUndo = key === 'z' && !e.shiftKey;
151→      if (!isUndo && !isRedo) return;
152→
153→      e.preventDefault();
154→      if (isRedo) {
155→        handleRedo();
156→        return;
157→      }
158→      handleUndo();
159→    };
160→
161→    window.addEventListener('keydown', handleKeyDown);
162→    return () => window.removeEventListener('keydown', handleKeyDown);
163→  }, [handleRedo, handleUndo]);
164→
165→  useEffect(() => {
166→    if (!toolMenuOpen) return;
167→    const handleClickOutside = (e) => {
168→      if (toolMenuRef.current && !toolMenuRef.current.contains(e.target)) {
169→        setToolMenuOpen(false);
170→      }
171→    };
172→    document.addEventListener('mousedown', handleClickOutside);
173→    return () => document.removeEventListener('mousedown', handleClickOutside);
174→  }, [toolMenuOpen]);
175→
176→  return (
177→    <div className={styles.toolbar}>
178→      <div className={styles.group}>
179→        <button className={styles.btn} onClick={onNew}>New</button>
180→        <button
181→          className={`${styles.btn} ${styles.iconBtn}`}
182→          onClick={handleUndo}
183→          disabled={!canUndo}
184→          title="Undo (Ctrl/Cmd+Z)"
185→          aria-label="Undo"
186→        >
187→          <UndoIcon />
188→        </button>
189→        <button
190→          className={`${styles.btn} ${styles.iconBtn}`}
191→          onClick={handleRedo}
192→          disabled={!canRedo}
193→          title="Redo (Ctrl/Cmd+Shift+Z or Ctrl/Cmd+Y)"
194→          aria-label="Redo"
195→        >
196→          <RedoIcon />
197→        </button>
198→        <button className={styles.btn} onClick={onSave}>
199→          {isDirty && <span className={styles.dirtyIndicator} />}
200→          Save
201→        </button>
202→        <button className={styles.btn} onClick={onLoad}>Load</button>
203→        <button
204→          className={styles.btn}
205→          onClick={copySelection}
206→          disabled={!canCopySelection}
207→          title="Copy Region (Ctrl/Cmd+C)"
208→        >
209→          Copy
210→        </button>
211→        <button
212→          className={styles.btn}
213→          onClick={cutSelection}
214→          disabled={!canCopySelection}
215→          title="Cut Region (Ctrl/Cmd+X)"
216→        >
217→          Cut
218→        </button>
219→        <button
220→          className={styles.btn}
221→          onClick={() => beginPaste()}
222→          disabled={!canPaste}
223→          title="Paste Region (Ctrl/Cmd+V)"
224→        >
225→          Paste
226→        </button>
227→      </div>
228→
229→      <div className={styles.group}>
230→        <button
231→          className={`${styles.btn} ${workspaceMode === 'model' && viewMode === 'plan' ? styles.active : ''}`}
232→          onClick={() => editorDispatch({ type: 'SET_VIEW_MODE', viewMode: 'plan' })}
233→          title="Plan View"
234→        >
235→          Plan
236→        </button>
237→        <button
238→          className={`${styles.btn} ${workspaceMode === 'model' && viewMode === 'elevation_front' ? styles.active : ''}`}
239→          onClick={() => editorDispatch({ type: 'SET_VIEW_MODE', viewMode: 'elevation_front' })}
240→          title="Front Elevation"
241→        >
242→          Front
243→        </button>
244→        <button
245→          className={`${styles.btn} ${workspaceMode === 'model' && viewMode === 'elevation_rear' ? styles.active : ''}`}
246→          onClick={() => editorDispatch({ type: 'SET_VIEW_MODE', viewMode: 'elevation_rear' })}
247→          title="Rear Elevation"
248→        >
249→          Rear
250→        </button>
251→        <button
252→          className={`${styles.btn} ${workspaceMode === 'model' && viewMode === 'elevation_left' ? styles.active : ''}`}
253→          onClick={() => editorDispatch({ type: 'SET_VIEW_MODE', viewMode: 'elevation_left' })}
254→          title="Left Elevation"
255→        >
256→          Left
257→        </button>
258→        <button
259→          className={`${styles.btn} ${workspaceMode === 'model' && viewMode === 'elevation_right' ? styles.active : ''}`}
260→          onClick={() => editorDispatch({ type: 'SET_VIEW_MODE', viewMode: 'elevation_right' })}
261→          title="Right Elevation"
262→        >
263→          Right
264→        </button>
265→        <button
266→          className={`${styles.btn} ${workspaceMode === 'model' && viewMode === 'section_view' ? styles.active : ''}`}
267→          onClick={() => editorDispatch({ type: 'SET_VIEW_MODE', viewMode: 'section_view' })}
268→          title="Section View"
269→        >
270→          Section
271→        </button>
272→        <button
273→          className={`${styles.btn} ${workspaceMode === 'sheet' ? styles.active : ''}`}
274→          onClick={() => editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'sheet' })}
275→          title="Sheet Workspace"
276→        >
277→          Sheets
278→        </button>
279→      </div>
280→
281→      <div className={styles.dropdown} ref={toolMenuRef}>
282→        <button
283→          className={`${styles.btn} ${styles.dropdownTrigger}`}
284→          onClick={() => setToolMenuOpen(!toolMenuOpen)}
285→          disabled={!isPlanView}
286→        >
287→          {activeToolLabel}
288→          <svg viewBox="0 0 10 6" className={styles.chevron} aria-hidden="true">
289→            <path d="M1 1l4 4 4-4" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
290→          </svg>
291→        </button>
292→        {toolMenuOpen && (
293→          <div className={styles.dropdownMenu}>
294→            {toolItems.map(({ tool, label, shortcut, hint }) => (
295→              <button
296→                key={tool}
297→                className={`${styles.dropdownItem} ${activeTool === tool ? styles.dropdownItemActive : ''}`}
298→                onClick={() => { setTool(tool); setToolMenuOpen(false); }}
299→                title={hint || ''}
300→              >
301→                <span>{label}</span>
302→                <kbd className={styles.shortcut}>{shortcut}</kbd>
303→              </button>
304→            ))}
305→          </div>
306→        )}
307→      </div>
308→
309→      <div className={styles.group}>
310→        <button
311→          className={`${styles.toggleBtn} ${!isSidebarCollapsed ? styles.toggleActive : ''} ${styles.iconBtn}`}
312→          onClick={onToggleSidebar}
313→          title={isSidebarCollapsed ? 'Show Sidebar' : 'Hide Sidebar'}
314→          aria-label={isSidebarCollapsed ? 'Show Sidebar' : 'Hide Sidebar'}
315→        >
316→          <SidebarIcon />
317→        </button>
318→        <button
319→          className={`${styles.toggleBtn} ${!isPropertiesCollapsed ? styles.toggleActive : ''} ${styles.iconBtn}`}
320→          onClick={onToggleProperties}
321→          title={isPropertiesCollapsed ? 'Show Properties Panel' : 'Hide Properties Panel'}
322→          aria-label={isPropertiesCollapsed ? 'Show Properties Panel' : 'Hide Properties Panel'}
323→        >
324→          <PropertiesIcon />
325→        </button>
326→        <button
327→          className={`${styles.toggleBtn} ${showGrid ? styles.toggleActive : ''}`}
328→          onClick={() => editorDispatch({ type: 'TOGGLE_GRID' })}
329→          title="Toggle Grid"
330→        >
331→          Grid
332→        </button>
333→        <button
334→          className={`${styles.toggleBtn} ${snapEnabled ? styles.toggleActive : ''}`}
335→          onClick={() => editorDispatch({ type: 'TOGGLE_SNAP' })}
336→          title="Toggle Snap"
337→        >
338→          Snap
339→        </button>
340→        <button
341→          className={styles.btn}
342→          onClick={handleDetectRooms}
343→          title="Auto-detect Rooms"
344→          disabled={!isPlanView}
345→        >
346→          Auto-detect Rooms
347→        </button>
348→      </div>
349→
350→      <div className={styles.spacer} />
351→    </div>
352→  );
353→}
